44	const CURSE_SURCHARGE_RATE = 0.5;
45	const HIGH_ENCHANTMENT_RATE = 0.3;
46	const HIGH_ENCHANTMENT_THRESHOLD = 5;
47	
48	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
49	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
50	  {
51	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
52	    rate: HIGH_ENCHANTMENT_RATE,
53	  },
54	];
55	
56	const itemSurcharge = (item: Item): number => {
57	  const base = BASE_PREMIUM[item.type];
58	  return sum(
59	    SURCHARGE_RULES.map((rule) => (rule.applies(item) ? base * rule.rate : 0)),
60	  );
61	};
62	
63	const itemSurcharges = (items: Item[]): number =>
64	  sum(items.map(itemSurcharge));
65	
66	const policyModifiers = (policyBase: number): number =>
67	  policyBase * FIRST_INSURANCE_RATE;
68	
69	const quote = (step: Step): { premium: number } => {
70	  const policyBase = itemsBasePremium(step.items);
71	  const total =
72	    policyBase +
73	    itemSurcharges(step.items) +
74	    policyModifiers(policyBase) +
75	    PROCESSING_FEE;
76	  return { premium: roundUpInMHPCOFavor(total) };
77	};
78	
79	export const runScenario = (input: unknown): unknown => {
80	  const scenario = input as Scenario;
81	  return { results: scenario.steps.map(quote) };
82	};
